import{_ as a,o as t,c as i,aA as n}from"./chunks/framework.BPXR-unS.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"LaMEM.jl","text":"Geodynamic modelling in Julia","tagline":"Set up, run and analyse LaMEM simulations directly from Julia — no manual PETSc or MPI installation required.","actions":[{"theme":"brand","text":"Get Started","link":"/installation"},{"theme":"alt","text":"Julia model setup","link":"/juliasetups"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/JuliaGeodynamics/LaMEM.jl"}],"image":{"light":"/assets/logo_LaMEM.png","dark":"/assets/logo_LaMEM_dark.png","alt":"LaMEM.jl logo"}},"features":[{"icon":"🚀","title":"Easy installation","details":"Automatically downloads LaMEM binaries with the correct PETSc and MPI for your platform (Linux, macOS, Windows).","link":"/installation"},{"icon":"🛠️","title":"Julia ecosystem","details":"Define geometry, materials, boundary conditions and solver options entirely in Julia with sensible defaults. Read LaMEM output back into Julia.","link":"/juliasetups"},{"icon":"▶️","title":"Run in parallel","details":"Launch LaMEM on multiple cores with a single function call — no manual mpiexec configuration needed.","link":"/runlamem"},{"icon":"🖥️","title":"HPC ready","details":"Prepare model files on a workstation and copy to a cluster to run large models there.","link":"/installation_HPC"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),o={name:"index.md"};function r(l,e,s,d,c,u){return t(),i("div",null,[...e[0]||(e[0]=[n('<h2 id="what-is-lamem" tabindex="-1">What is LaMEM? <a class="header-anchor" href="#what-is-lamem" aria-label="Permalink to &quot;What is LaMEM?&quot;">​</a></h2><p><code>LaMEM</code> (<strong>L</strong>ithosphere <strong>a</strong>nd <strong>M</strong>antle <strong>E</strong>volution <strong>M</strong>odel) is a parallel 3D numerical code for thermo-mechanical geodynamical simulations. Key features include:</p><ul><li>Visco-elasto-plastic rheologies for mantle-lithosphere interaction</li><li>Geomechanical problems, (compressible) poroelasticity, and a gravity solver</li><li>Adjoint inversion framework</li><li>Marker-in-cell approach with staggered finite difference discretization</li><li>Built on top of PETSc — runs on anything from a laptop to a massively parallel machine</li><li>(Galerkin) multigrid and iterative solvers for linear and non-linear rheologies, using Picard and quasi-Newton solvers</li><li>Tested on large parallel machines on up to 458&#39;752 cores</li></ul><p><code>LaMEM.jl</code> provides a Julia interface to <code>LaMEM</code> that handles installation, model setup, job execution and postprocessing.</p><h2 id="citation" tabindex="-1">Citation <a class="header-anchor" href="#citation" aria-label="Permalink to &quot;Citation&quot;">​</a></h2><p>If you use LaMEM in your research, please cite the original peer-reviewed extended abstract that describes it:</p><ul><li>Kaus, B.J.P., Popov, A.A., Baumann, T., Pusok, A., Bauville, A., Fernandez, N., Collignon, M. (2016). Forward and Inverse Modelling of Lithospheric Deformation on Geological Timescales. <em>NIC Series</em>, 48, 299-306, <a href="https://juser.fz-juelich.de/record/507751/files/nic_2016_kaus.pdf" target="_blank" rel="noreferrer">ISBN:978-3-95806-109-5</a>.</li></ul><p>A more recent publication that gives some more recent details is:</p><ul><li>Schuler, C., Kaus, B.J.P., Breton, E.L., Riel, N., Popov, A.A., 2025. Mantle Dynamics in the Mediterranean and Plate Motion of the Adriatic Microplate: Insights From 3D Thermomechanical Modeling. Geochemistry, Geophysics, Geosystems 26, e2024GC011996. <a href="https://doi.org/10.1029/2024GC011996" target="_blank" rel="noreferrer">https://doi.org/10.1029/2024GC011996</a></li></ul><p>And for reproducibility reasons, you should always cite the correct version number you use. For LaMEM.jl that is given by the most recent version of the code on <a href="https://zenodo.org/records/18842336" target="_blank" rel="noreferrer">zenodo</a>.</p><h2 id="funding" tabindex="-1">Funding <a class="header-anchor" href="#funding" aria-label="Permalink to &quot;Funding&quot;">​</a></h2><p>LaMEM is an open source software project mainly developed at the Johannes-Gutenberg University in Mainz (Germany). The key funding came from:</p><ul><li>The European Research Council through Grants ERC StG 258830 (MODEL), ERC PoC 713397 (SALTED) and ERC CoG 771143 (MAGMA)</li><li>The German ministry of Science and Eduction (BMBF) through projects SECURE, PERMEA, and PERMEA2.</li><li>Priority programs of the German research foundation (DFG), specifically the <a href="http://www.spp-mountainbuilding.de" target="_blank" rel="noreferrer">4DMB</a> and <a href="https://habitableearth.uni-koeln.de" target="_blank" rel="noreferrer">Habitable Earth</a> projects.</li></ul><p>The development of the Julia interface to LaMEM was supported by the European Research Council under grant ERC CoG #771143 - <a href="https://magma.uni-mainz.de" target="_blank" rel="noreferrer">MAGMA</a> and by the EuroHPC Center of Excellence <a href="https://cheese2.eu" target="_blank" rel="noreferrer">ChEESE-2p</a>.</p>',14)])])}const m=a(o,[["render",r]]);export{p as __pageData,m as default};
